// =========================================================================
// BƯỚC 2: HỆ THỐNG THUẬT TOÁN XỬ LÝ LOGIC (CHÍNH XÁC TUYỆT ĐỐI BẰNG KIỂM TRA KÉP)
// =========================================================================

let danhSachHocSinh = [];
let loaiHienTai = "";
let tenTepXuat = "";
let tenLopThucTe = "";

function layNgauNhien(arr) { 
    if (!arr || arr.length === 0 || arr[0] === "...") return "";
    return arr[Math.floor(Math.random() * arr.length)]; 
}

function xepLoaiMonHoc(diemStr) {
    let d = " " + String(diemStr).toUpperCase().replace(/\s+/g, ' ') + " ";
    if (d.includes(' C ') || d.match(/\b[1-4]\b/)) return 'C';
    if (d.includes(' H ') || d.match(/\b[5-6]\b/)) return 'H';
    if (d.includes(' T ') || d.match(/\b([7-9]|10)\b/)) return 'T';
    return 'H'; 
}

function xepLoaiNangLuc(diemStr) {
    let d = " " + String(diemStr).toUpperCase().replace(/\s+/g, ' ') + " ";
    if (d.includes(' C ')) return 'C'; 
    if (d.includes(' Đ ') || d.includes(' D ')) return 'D'; 
    if (d.includes(' T ')) return 'T'; 
    return 'D'; 
}

async function batDauXuLy() {
    // 1. LỆNH XÓA SẠCH DỮ LIỆU CŨ: Đảm bảo không bị cộng dồn khi bấm nhiều lần
    danhSachHocSinh = []; 
    document.getElementById('tableContainer').innerHTML = "";
    document.getElementById('previewArea').style.display = 'none';
    
    const filesExcel = document.getElementById('fileUpload').files;
    const selectLoai = document.getElementById('loaiBangDiem');
    const selectKhoi = document.getElementById('khoiLop');
    
    loaiHienTai = selectLoai.value;
    const khoiHienTai = selectKhoi.value;
    const tenLopInput = document.getElementById('tenLop');
    tenLopThucTe = tenLopInput ? tenLopInput.value.trim() : "";
    
    const moTaLoai = selectLoai.options[selectLoai.selectedIndex].text;
    tenTepXuat = `NhanXet_${tenLopThucTe ? tenLopThucTe + "_" : ""}${moTaLoai.replace(/ /g, "_")}.docx`;
    document.getElementById('tenTepHienThi').innerText = tenTepXuat;

    if (filesExcel.length === 0 || !tenLopThucTe) {
        return alert("Vui lòng nhập Tên lớp và tải lên file Bảng điểm Excel!");
    }

    document.getElementById('status').style.color = "#0066cc";
    document.getElementById('status').innerText = "Hệ thống đang trích xuất và đồng bộ dữ liệu đa Sheet...\nVui lòng đợi...";
    await new Promise(resolve => setTimeout(resolve, 100));
    
    for (let i = 0; i < filesExcel.length; i++) {
        const arrayBuffer = await filesExcel[i].arrayBuffer();
        const workbook = XLSX.read(arrayBuffer, {type: 'array'});
        
        workbook.SheetNames.forEach(sheetName => {
            const sheet = workbook.Sheets[sheetName];
            const rawData = XLSX.utils.sheet_to_json(sheet, {header: 1});
            
            let cotHoTen = -1;
            let dongBatDau = -1;

            // Tìm vị trí cột chứa "Họ và tên"
            for (let r = 0; r < rawData.length; r++) {
                if (rawData[r]) {
                    for (let c = 0; c < rawData[r].length; c++) {
                        if (typeof rawData[r][c] === 'string' && rawData[r][c].toLowerCase().includes("họ và tên")) {
                            cotHoTen = c; dongBatDau = r + 1; break;
                        }
                    }
                }
                if (cotHoTen !== -1) break;
            }

            if (cotHoTen !== -1) {
                let sttHocSinhTrongSheet = 0; // Biến đếm vị trí học sinh
                
                for (let r = dongBatDau; r < rawData.length; r++) {
                    let ten = rawData[r][cotHoTen];
                    if (ten && typeof ten === 'string' && isNaN(ten) && ten.trim().length > 4) {
                        let tenHS = ten.trim();
                        let tenLower = tenHS.toLowerCase();
                        
                        // Lọc bỏ các dòng tiêu đề rác của SMAS
                        if (!tenLower.includes("trường") && !tenLower.includes("hiệu trưởng") && 
                            !tenLower.includes("giáo viên") && !tenLower.includes("người lập")) {
                            
                            let diemSoCuaMon = [];
                            for (let c = cotHoTen + 1; c < rawData[r].length; c++) {
                                if (rawData[r][c] !== undefined && rawData[r][c] !== "") {
                                    diemSoCuaMon.push(String(rawData[r][c]).trim());
                                }
                            }
                            
                            // THUẬT TOÁN ĐỒNG BỘ "KIỂM TRA KÉP" (VỊ TRÍ + TÊN)
                            if (!danhSachHocSinh[sttHocSinhTrongSheet]) {
                                // Sheet đầu tiên: Tạo mới danh sách 38 học sinh (Ví dụ)
                                danhSachHocSinh.push({
                                    hoTen: tenHS,
                                    diemSo: diemSoCuaMon.join(" ")
                                });
                            } else {
                                // Từ Sheet thứ 2: Kiểm tra xem TÊN ở vị trí này có khớp y hệt Sheet 1 không
                                if (danhSachHocSinh[sttHocSinhTrongSheet].hoTen === tenHS) {
                                    // Nếu khớp chính xác tuyệt đối -> Gộp điểm vào
                                    danhSachHocSinh[sttHocSinhTrongSheet].diemSo += " " + diemSoCuaMon.join(" ");
                                }
                            }
                            // Tăng số thứ tự để xét em tiếp theo
                            sttHocSinhTrongSheet++;
                        }
                    }
                }
            }
        });
    }
    
    if(danhSachHocSinh.length === 0) {
        document.getElementById('status').innerText = "";
        return alert("Không tìm thấy dữ liệu học sinh hợp lệ!");
    }

    danhSachHocSinh.forEach(hs => {
        // Học sinh không có điểm (Bôi đỏ / Chuyển trường) -> Để trống tuyệt đối
        if (hs.diemSo.trim() === "") {
            if (loaiHienTai === "monHoc") {
                hs.nhanXetMonHoc1 = ""; hs.nhanXetMonHoc2 = ""; hs.nhanXetMonHoc3 = "";
            } else {
                hs.nangLucChung = ""; hs.nangLucDacThu = ""; hs.phamChat = "";
            }
            return; 
        }

        if (loaiHienTai === "monHoc") {
            let mucDo = xepLoaiMonHoc(hs.diemSo);
            let dataKhoi = khoDuLieu.monHoc[khoiHienTai][mucDo];
            hs.nhanXetMonHoc1 = layNgauNhien(dataKhoi.cau1);
            hs.nhanXetMonHoc2 = layNgauNhien(dataKhoi.cau2);
            hs.nhanXetMonHoc3 = layNgauNhien(dataKhoi.cau3);
        } else {
            let mucDo = xepLoaiNangLuc(hs.diemSo);
            let dataKhoi = khoDuLieu.nangLuc[khoiHienTai][mucDo];
            hs.nangLucChung = layNgauNhien(dataKhoi.nlc);
            hs.nangLucDacThu = layNgauNhien(dataKhoi.nldt);
            hs.phamChat = layNgauNhien(dataKhoi.pc);
        }
    });

    document.getElementById('status').style.color = "#28a745"; 
    document.getElementById('status').innerText = "✅ Xử lý thành công! Số lượng học sinh đồng bộ chính xác 100%.";
    hienThiBang();
}

function hienThiBang() {
    document.getElementById('previewArea').style.display = 'block';
    const container = document.getElementById('tableContainer');
    
    let html = '<table id="bangKetQua">';
    if (loaiHienTai === 'monHoc') {
        html += '<thead><tr><th style="width: 20%; font-weight: bold; color: #004085;">Họ và tên</th><th style="font-weight: bold; color: #004085;">Nhận xét dòng 1</th><th style="font-weight: bold; color: #004085;">Nhận xét dòng 2</th><th style="font-weight: bold; color: #004085;">Nhận xét dòng 3</th></tr></thead><tbody>';
        danhSachHocSinh.forEach(hs => {
            html += `<tr><td style="font-weight: bold; color: #004085;">${hs.hoTen}</td><td style="text-align: justify; line-height: 1.6;">${hs.nhanXetMonHoc1}</td><td style="text-align: justify; line-height: 1.6;">${hs.nhanXetMonHoc2}</td><td style="text-align: justify; line-height: 1.6;">${hs.nhanXetMonHoc3}</td></tr>`;
        });
    } else {
        html += '<thead><tr><th style="width: 20%; font-weight: bold; color: #004085;">Họ và tên</th><th style="font-weight: bold; color: #004085;">Đánh giá năng lực chung</th><th style="font-weight: bold; color: #004085;">Đánh giá năng lực đặc thù</th><th style="font-weight: bold; color: #004085;">Phẩm chất</th></tr></thead><tbody>';
        danhSachHocSinh.forEach(hs => {
            html += `<tr><td style="font-weight: bold; color: #004085;">${hs.hoTen}</td><td style="text-align: justify; line-height: 1.6;">${hs.nangLucChung}</td><td style="text-align: justify; line-height: 1.6;">${hs.nangLucDacThu}</td><td style="text-align: justify; line-height: 1.6;">${hs.phamChat}</td></tr>`;
        });
    }
    html += '</tbody></table>';
    container.innerHTML = html;
}

function xuatFileWord() {
    let tieuDeInDam = loaiHienTai === 'monHoc' 
        ? `ĐÁNH GIÁ MÔN HỌC VÀ HĐGD LỚP ${tenLopThucTe}`.toUpperCase()
        : `ĐÁNH GIÁ NĂNG LỰC VÀ PHẨM CHẤT LỚP ${tenLopThucTe}`.toUpperCase();

    const tieuDeLop = new docx.Paragraph({
        alignment: docx.AlignmentType.CENTER,
        spacing: { after: 300 }, 
        children: [
            new docx.TextRun({
                text: tieuDeInDam,
                bold: true,
                size: 32, 
                font: "Times New Roman"
            })
        ]
    });

    const rows = [];
    if (loaiHienTai === 'monHoc') {
        rows.push(new docx.TableRow({ children: [
            new docx.TableCell({ children: [new docx.Paragraph({ children: [new docx.TextRun({ text: "Họ và tên", bold: true })] })] }),
            new docx.TableCell({ children: [new docx.Paragraph({ children: [new docx.TextRun({ text: "Nhận xét dòng 1", bold: true })] })] }),
            new docx.TableCell({ children: [new docx.Paragraph({ children: [new docx.TextRun({ text: "Nhận xét dòng 2", bold: true })] })] }),
            new docx.TableCell({ children: [new docx.Paragraph({ children: [new docx.TextRun({ text: "Nhận xét dòng 3", bold: true })] })] })
        ]}));
        
        danhSachHocSinh.forEach(hs => {
            rows.push(new docx.TableRow({ children: [
                new docx.TableCell({ children: [new docx.Paragraph({ children: [new docx.TextRun({ text: hs.hoTen, bold: true })] })] }),
                new docx.TableCell({ children: [new docx.Paragraph({ text: hs.nhanXetMonHoc1, alignment: docx.AlignmentType.JUSTIFIED })] }),
                new docx.TableCell({ children: [new docx.Paragraph({ text: hs.nhanXetMonHoc2, alignment: docx.AlignmentType.JUSTIFIED })] }),
                new docx.TableCell({ children: [new docx.Paragraph({ text: hs.nhanXetMonHoc3, alignment: docx.AlignmentType.JUSTIFIED })] })
            ]}));
        });
    } else {
        rows.push(new docx.TableRow({ children: [
            new docx.TableCell({ children: [new docx.Paragraph({ children: [new docx.TextRun({ text: "Họ và tên", bold: true })] })] }),
            new docx.TableCell({ children: [new docx.Paragraph({ children: [new docx.TextRun({ text: "Đánh giá năng lực chung", bold: true })] })] }),
            new docx.TableCell({ children: [new docx.Paragraph({ children: [new docx.TextRun({ text: "Đánh giá năng lực đặc thù", bold: true })] })] }),
            new docx.TableCell({ children: [new docx.Paragraph({ children: [new docx.TextRun({ text: "Phẩm chất", bold: true })] })] })
        ]}));
        
        danhSachHocSinh.forEach(hs => {
            rows.push(new docx.TableRow({ children: [
                new docx.TableCell({ children: [new docx.Paragraph({ children: [new docx.TextRun({ text: hs.hoTen, bold: true })] })] }),
                new docx.TableCell({ children: [new docx.Paragraph({ text: hs.nangLucChung, alignment: docx.AlignmentType.JUSTIFIED })] }),
                new docx.TableCell({ children: [new docx.Paragraph({ text: hs.nangLucDacThu, alignment: docx.AlignmentType.JUSTIFIED })] }),
                new docx.TableCell({ children: [new docx.Paragraph({ text: hs.phamChat, alignment: docx.AlignmentType.JUSTIFIED })] })
            ]}));
        });
    }
    
    const table = new docx.Table({ rows: rows, width: { size: 100, type: docx.WidthType.PERCENTAGE } });
    const doc = new docx.Document({ sections: [{ children: [tieuDeLop, table] }] });

    docx.Packer.toBlob(doc).then(blob => {
        const link = document.createElement("a");
        link.href = URL.createObjectURL(blob);
        link.download = tenTepXuat;
        link.click();
    });
}